// BEFORE (error):
int* getNumber() {
    int x = 42;
    return &x; // dangling pointer after return
}

// AFTER (fix — return by value):
int getNumber() {
    int x = 42;
    return x;
}

// AFTER (fix — heap allocation with smart pointer):
