if (condition) count = 5;
printf("%d", count); // always initialized

// BEFORE (wrong):
void process(int arr[]) {
    size_t len = sizeof(arr) / sizeof(arr[0]); // BUG: sizeof(int*) / sizeof(int)
}

// AFTER (fix — pass size):
void process(int arr[], size_t len) {
    for (size_t i = 0; i < len; i++) { /*...*/ }
}

// AFTER (fix — use vector):
void process(const std::vector<int>& arr) {
    size_t len = arr.size();
}

