#include "myclass.h"    // corresponding header first
#include <cstdlib>       // C system headers
#include <vector>        // C++ standard headers
#include <boost/asio.hpp> // library headers
#include "utils.h"       // project headers

// WRONG — in header.h:
int count = 0;  // definition in header, ODR violation if included in 2+ .cpp

// CORRECT — in header.h:
extern int count;  // declaration only
inline int helper() { return 42; }  // inline is OK
constexpr int MAX = 100;  // constexpr is implicitly inline in C++17

// WRONG — template in .cpp:
// math.h
template<typename T> T add(T a, T b);
// math.cpp
template<typename T> T add(T a, T b) { return a + b; }
// LINKER ERROR: undefined reference to add<int>

// CORRECT — template in header:
// math.h
template<typename T> T add(T a, T b) { return a + b; }

// ALTERNATIVE — explicit instantiation:
// math.cpp
template<typename T> T add(T a, T b) { return a + b; }
template int add<int>(int, int);  // explicit instantiation

// Most vexing parse — this declares a FUNCTION, not an object:
Foo f(Bar());  // f is a function taking a function pointer

// Fix with braces (C++11):
Foo f{Bar{}};  // f is a Foo object

// Fix with extra parentheses:
Foo f((Bar()));  // f is a Foo object

// ADL finds operator<< in namespace std:
std::cout << "hello";  // works without 'using namespace std'

// Custom namespace ADL:
namespace mylib {
    struct Widget {};
    void process(Widget w) {}
}
mylib::Widget w;
process(w);  // found via ADL in mylib namespace

template<typename T>
class Derived : public Base<T> {
    void foo() {
        // WRONG: 'bar' not found (phase-1 lookup)
        bar();
        // CORRECT: deferred to phase-2 lookup
        this->bar();
        Base<T>::bar();
    }
};

// DANGEROUS — fiasco prone:
// a.cpp
extern int y;
int x = y + 1;  // y may not be initialized yet

// SAFE — construct on first use:
int& getX() {
    static int x = getY() + 1;
    return x;
}

// Traditional include guard:
#ifndef MY_HEADER_H
#define MY_HEADER_H

// ... header contents ...

#endif // MY_HEADER_H

// Modern alternative:
#pragma once

// ... header contents ...

// SURPRISING implicit conversion:
class Foo {
public:
    Foo(int x) {}  // implicit conversion from int
};
void bar(Foo f);
bar(42);  // compiles! implicit Foo(42)

// SAFE with explicit:
class Foo {
public:
    explicit Foo(int x) {}
};
bar(42);         // ERROR: no implicit conversion
bar(Foo(42));    // OK: explicit construction

